import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../services/api';
import '../styles/Katalog.css';

const Profile = ({ user }) => {
  const navigate = useNavigate();
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  const storedUser = user || JSON.parse(localStorage.getItem('campbread_user') || 'null');

  useEffect(() => {
    if (!storedUser) {
      navigate('/login');
      return;
    }
    fetchOrders();
  }, [storedUser]);

  const fetchOrders = async () => {
    setLoading(true);
    try {
      const response = await API.get('/orders');
      setOrders(response.data);
    } catch (error) {
      console.error('Gagal memuat riwayat pesanan:', error);
    } finally {
      setLoading(false);
    }
  };

  if (!storedUser) {
    return null;
  }

  return (
    <div className="katalog-wrapper">
      <div className="katalog-overlay"></div>
      <div className="katalog-content" style={{ maxWidth: '980px', margin: '0 auto', padding: '40px 20px' }}>
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '24px', marginBottom: '30px' }}>
          <div style={{ flex: '1', minWidth: '280px', background: 'white', borderRadius: '12px', padding: '25px', boxShadow: '0 10px 30px rgba(0,0,0,0.08)' }}>
            <h2 style={{ margin: '0 0 15px', fontSize: '22px', color: '#111827' }}>Profil Pelanggan</h2>
            <div style={{ marginBottom: '12px' }}><strong>Nama:</strong> {storedUser.name}</div>
            <div style={{ marginBottom: '12px' }}><strong>Email:</strong> {storedUser.email}</div>
            <div style={{ marginBottom: '12px' }}><strong>Peran:</strong> {storedUser.role}</div>
          </div>
          <div style={{ flex: '2', minWidth: '300px', background: 'white', borderRadius: '12px', padding: '25px', boxShadow: '0 10px 30px rgba(0,0,0,0.08)' }}>
            <h2 style={{ margin: '0 0 15px', fontSize: '22px', color: '#111827' }}>Riwayat Pesanan</h2>
            {loading ? (
              <p style={{ color: '#6b7280' }}>Memuat riwayat pesanan...</p>
            ) : orders.length === 0 ? (
              <p style={{ color: '#6b7280' }}>Belum ada pesanan.</p>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {orders.map((order) => (
                  <div key={order.id} style={{ border: '1px solid #e5e7eb', borderRadius: '10px', padding: '18px' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', flexWrap: 'wrap', gap: '12px', marginBottom: '12px' }}>
                      <div>
                        <div style={{ fontWeight: 'bold', marginBottom: '6px' }}>Pesanan #{order.id}</div>
                        <div style={{ fontSize: '13px', color: '#6b7280' }}>{new Date(order.createdAt).toLocaleString('id-ID')}</div>
                      </div>
                      <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                        <span style={{ padding: '6px 12px', borderRadius: '999px', background: '#e5e7ff', color: '#3730a3', fontSize: '12px', fontWeight: 'bold' }}>{order.status}</span>
                        <span style={{ padding: '6px 12px', borderRadius: '999px', background: '#f3f4f6', color: '#374151', fontSize: '12px' }}>Total: Rp {Number(order.totalAmount).toLocaleString('id-ID')}</span>
                      </div>
                    </div>
                    <div style={{ marginBottom: '12px', color: '#4b5563' }}><strong>Catatan Pesanan:</strong> {order.note || 'Tidak ada catatan'}</div>
                    <div style={{ borderTop: '1px solid #e5e7eb', paddingTop: '12px' }}>
                      {order.items.map((item) => (
                        <div key={item.id} style={{ marginBottom: '8px' }}>
                          <div style={{ fontWeight: 'bold' }}>{item.productName} x{item.quantity}</div>
                          <div style={{ fontSize: '13px', color: '#6b7280' }}>Harga per item: Rp {Number(item.price).toLocaleString('id-ID')}{item.note ? ` · Catatan: ${item.note}` : ''}</div>
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;
